  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import {
  3→    createStarEngine,
  4→    createStarBody,
  5→    createConstellationConstraint,
  6→    getStarMass,
  7→    PHYSICS_CONFIG,
  8→    Engine,
  9→    Body,
 10→    World,
 11→    Constraint,
 12→} from '../physics/matterEngine';
 13→import { buildSemanticMaps } from '../physics/semanticForces';
 14→import { buildQuadTree, computeBarnesHutForces } from '../physics/barnesHut';
 15→import { screenToWorld } from '../utils/coordConversion';
 16→import { userHomeCoords, getStarRadius } from '../utils/starUtils';
 17→
 18→/**
 19→ * useStarPhysics — owns the Matter.js engine for star-level physics.
 20→ *
 21→ * Stars get real velocity, collision, air friction, semantic gravity,
 22→ * constellation constraints, and interactive drag-and-throw.
 23→ */
 24→export default function useStarPhysics({
 25→    posts,
 26→    activePostIds,
 27→    galaxyPositions,
 28→    starPulls,
 29→    similarPairs,
 30→    starPullOffsets,
 31→    isGalaxySettled,
 32→    camera,
 33→    zoom,
 34→    stageSize,
 35→    isStarDragging,
 36→    enabled = true,
 37→}) {
 38→    const [starBodyPositions, setStarBodyPositions] = useState(() => new Map());
 39→
 40→    // Refs for the physics engine — not in React state
 41→    const engineRef = useRef(null);
 42→    const bodiesRef = useRef(new Map());          // postId → Matter.Body
 43→    const anchorsRef = useRef(new Map());          // postId → {x, y} anchor target
 44→    const constraintsRef = useRef(new Map());      // "postA|postB" → Matter.Constraint
 45→    const staticTimesRef = useRef(new Map());      // postId → timestamp when set to static
 46→    const rafRef = useRef(null);
 47→    const frameCountRef = useRef(0);
 48→    const lastCleanupRef = useRef(Date.now());
 49→
 50→    // Drag state
 51→    const dragBodyRef = useRef(null);
 52→    const dragConstraintRef = useRef(null);
 53→    const dragPointRef = useRef(null);             // {x,y} fixed world point
 54→
 55→    // Keep latest values in refs for the RAF loop (avoids stale closures)
 56→    const galaxyPositionsRef = useRef(galaxyPositions);
 57→    const semanticMapsRef = useRef({ starPullMap: new Map(), pairMap: new Map() });
 58→    const cameraRef = useRef(camera);
 59→    const zoomRef = useRef(zoom);
 60→    const stageSizeRef = useRef(stageSize);
 61→    const postsMapRef = useRef(new Map());
 62→
 63→    // Sync refs
 64→    galaxyPositionsRef.current = galaxyPositions;
 65→    cameraRef.current = camera;
 66→    zoomRef.current = zoom;
 67→    stageSizeRef.current = stageSize;
 68→
 69→    // Build a postId → post lookup
 70→    useEffect(() => {
 71→        const map = new Map();
 72→        if (Array.isArray(posts)) {
 73→            for (const p of posts) {
 74→                if (p?.id) map.set(p.id, p);
 75→            }
 76→        }
 77→        postsMapRef.current = map;
 78→    }, [posts]);
 79→
 80→    // Pre-process semantic data into O(1) maps
 81→    useEffect(() => {
 82→        semanticMapsRef.current = buildSemanticMaps(starPulls, similarPairs);
 83→    }, [starPulls, similarPairs]);
 84→
 85→    // ── Create engine on mount ────────────────────────────────────────
 86→    useEffect(() => {
 87→        if (!enabled) return;
 88→
 89→        engineRef.current = createStarEngine();
 90→
 91→        return () => {
 92→            if (rafRef.current) {
 93→                cancelAnimationFrame(rafRef.current);
 94→                rafRef.current = null;
 95→            }
 96→            if (engineRef.current) {
 97→                World.clear(engineRef.current.world, false);
 98→                Engine.clear(engineRef.current);
 99→                engineRef.current = null;
100→            }
101→            bodiesRef.current.clear();
102→            anchorsRef.current.clear();
103→            constraintsRef.current.clear();
104→            staticTimesRef.current.clear();
105→        };
106→    }, [enabled]);
107→
108→    // ── Helper: compute a star's static position (same as getComputedStarPosition) ─
109→    const computeStaticPosition = useCallback((post) => {
110→        if (!post) return null;
111→        const uid = post.users?.id ?? post.user_id;
112→        const hashGal = userHomeCoords(uid);
113→        const animGal = galaxyPositionsRef.current?.get(uid);
114→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
115→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
116→        const pull = starPullOffsets?.get(post.id);
117→
118→        const baseX = post.universe_x ?? post.display_x;
119→        const baseY = post.universe_y ?? post.display_y;
120→        if (baseX == null || baseY == null) return null;
121→
122→        return {
123→            x: baseX + galDx + (pull?.dx ?? 0),
124→            y: baseY + galDy + (pull?.dy ?? 0),
125→        };
126→    }, [starPullOffsets]);
127→
128→    // ── Body lifecycle: create/activate/deactivate based on activePostIds ──
129→    useEffect(() => {
130→        if (!enabled || !engineRef.current) return;
131→        if (!(activePostIds instanceof Set) || activePostIds.size === 0) return;
132→
133→        const engine = engineRef.current;
134→        const bodies = bodiesRef.current;
135→        const anchors = anchorsRef.current;
136→        const staticTimes = staticTimesRef.current;
137→
138→        // Activate or create bodies for active posts
139→        let created = 0;
140→        for (const postId of activePostIds) {
141→            if (created >= PHYSICS_CONFIG.maxActiveBodies) break;
142→
143→            const existing = bodies.get(postId);
144→            if (existing) {
145→                // Re-awaken if it was static
146→                if (existing.isStatic) {
147→                    Body.setStatic(existing, false);
148→                    staticTimes.delete(postId);
149→                }
150→                created++;
151→                continue;
152→            }
153→
154→            // Create new body
155→            const post = postsMapRef.current.get(postId);
156→            if (!post) continue;
157→
158→            const pos = computeStaticPosition(post);
159→            if (!pos) continue;
160→
161→            const likeCount = post.like_count != null
162→                ? post.like_count
163→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
164→                    ? post.likes[0].count : 0);
165→            const radius = getStarRadius(likeCount);
166→            const mass = getStarMass(likeCount);
167→
168→            const body = createStarBody(postId, pos.x, pos.y, radius, mass);
169→            World.add(engine.world, body);
170→            bodies.set(postId, body);
171→            anchors.set(postId, { x: pos.x, y: pos.y });
172→            created++;
173→        }
174→
175→        // Deactivate bodies that left active set → make static
176→        for (const [postId, body] of bodies.entries()) {
177→            if (!activePostIds.has(postId) && !body.isStatic) {
178→                Body.setStatic(body, true);
179→                staticTimes.set(postId, Date.now());
180→            }
181→        }
182→    }, [enabled, activePostIds, computeStaticPosition]);
183→
184→    // ── Constellation constraints from similarPairs ────────────────────
185→    useEffect(() => {
186→        if (!enabled || !engineRef.current) return;
187→
188→        const engine = engineRef.current;
189→        const bodies = bodiesRef.current;
190→        const constraints = constraintsRef.current;
191→        const { pairMap } = semanticMapsRef.current;
192→
193→        // Remove old constraints
194→        for (const [key, constraint] of constraints.entries()) {
195→            World.remove(engine.world, constraint);
196→            constraints.delete(key);
197→        }
198→
199→        if (pairMap.size === 0) return;
200→
201→        // Build new constraints where both bodies are active
202→        const seen = new Set();
203→        for (const [postId, pairs] of pairMap.entries()) {
204→            const bodyA = bodies.get(postId);
205→            if (!bodyA || bodyA.isStatic) continue;
206→
207→            for (const { otherPostId, similarity } of pairs) {
208→                const pairKey = postId < otherPostId
209→                    ? `${postId}|${otherPostId}`
210→                    : `${otherPostId}|${postId}`;
211→                if (seen.has(pairKey)) continue;
212→                seen.add(pairKey);
213→
214→                const bodyB = bodies.get(otherPostId);
215→                if (!bodyB || bodyB.isStatic) continue;
216→
217→                const constraint = createConstellationConstraint(bodyA, bodyB, similarity);
218→                World.add(engine.world, constraint);
219→                constraints.set(pairKey, constraint);
220→            }
221→        }
222→    }, [enabled, similarPairs, activePostIds]);
223→
224→    // ── Update anchor targets when galaxy positions change ──────────────
225→    useEffect(() => {
226→        if (!enabled) return;
227→        const anchors = anchorsRef.current;
228→        const bodies = bodiesRef.current;
229→
230→        for (const [postId] of bodies.entries()) {
231→            const post = postsMapRef.current.get(postId);
232→            if (!post) continue;
233→            const pos = computeStaticPosition(post);
234→            if (pos) {
235→                anchors.set(postId, pos);
236→            }
237→        }
238→    }, [enabled, galaxyPositions, starPullOffsets, computeStaticPosition]);
239→
240→    // ── RAF loop: apply forces + step engine + push positions ──────────
241→    useEffect(() => {
242→        if (!enabled || !engineRef.current) return;
243→
244→        let active = true;
245→
246→        const tick = () => {
247→            if (!active || !engineRef.current) return;
248→
249→            const engine = engineRef.current;
250→            const bodies = bodiesRef.current;
251→            const anchors = anchorsRef.current;
252→            const staticTimes = staticTimesRef.current;
253→            const { pairMap } = semanticMapsRef.current;
254→            const galPositions = galaxyPositionsRef.current;
255→
256→            // ── Build body array (stars only — no galaxy centers) ──
257→            const bodyArray = [];
258→            const draggedId = dragBodyRef.current?.label ?? null;
259→
260→            for (const [postId, body] of bodies.entries()) {
261→                if (body.isStatic || body.isSleeping) continue;
262→                bodyArray.push({
263→                    id: postId,
264→                    x: body.position.x,
265→                    y: body.position.y,
266→                    mass: body.mass,
267→                });
268→            }
269→
270→            // ── Barnes-Hut N-body (star-to-star semantic forces only) ──
271→            const root = buildQuadTree(bodyArray);
272→            const forces = computeBarnesHutForces(root, bodyArray, {
273→                G: PHYSICS_CONFIG.nBodyG,
274→                theta: PHYSICS_CONFIG.nBodyTheta,
275→                softening: PHYSICS_CONFIG.nBodySoftening,
276→                maxForce: PHYSICS_CONFIG.nBodyMaxForce,
277→                pairMap,
278→            });
279→
280→            // ── Apply forces per post ──
281→            for (const [postId, body] of bodies.entries()) {
282→                if (body.isStatic || body.isSleeping) continue;
283→                if (postId === draggedId) continue;
284→
285→                // Inter-star semantic gravity (N-body)
286→                const force = forces.get(postId);
287→                if (force) {
288→                    Body.applyForce(body, body.position, {
289→                        x: force.fx,
290→                        y: force.fy,
291→                    });
292→                }
293→
294→                // Orbit forces: radial spring + tangential drive
295→                const post = postsMapRef.current.get(postId);
296→                if (post) {
297→                    const uid = post.users?.id ?? post.user_id;
298→                    const galPos = galPositions?.get(uid);
299→                    const anchor = anchors.get(postId);
300→                    if (galPos && anchor) {
301→                        // Target orbit radius = original distance from galaxy center
302→                        const origDx = anchor.x - galPos.x;
303→                        const origDy = anchor.y - galPos.y;
304→                        const targetRadius = Math.max(
305→                            Math.sqrt(origDx * origDx + origDy * origDy),
306→                            40 // minimum orbit radius
307→                        );
308→
309→                        // Current position relative to galaxy center
310→                        const dx = body.position.x - galPos.x;
311→                        const dy = body.position.y - galPos.y;
312→                        const dist = Math.sqrt(dx * dx + dy * dy);
313→
314→                        if (dist > 1) {
315→                            const invDist = 1 / dist;
316→
317→                            // Radial spring: push/pull toward target orbit radius
318→                            // Positive = outward (too close), negative = inward (too far)
319→                            const radialForce = (targetRadius - dist) * PHYSICS_CONFIG.orbitSpringK;
320→                            Body.applyForce(body, body.position, {
321→                                x: dx * invDist * radialForce * body.mass,
322→                                y: dy * invDist * radialForce * body.mass,
323→                            });
324→
325→                            // Tangential drive: constant perpendicular push to maintain rotation
326→                            const tanX = -dy * invDist;
327→                            const tanY = dx * invDist;
328→                            Body.applyForce(body, body.position, {
329→                                x: tanX * PHYSICS_CONFIG.orbitalDrive * body.mass,
330→                                y: tanY * PHYSICS_CONFIG.orbitalDrive * body.mass,
331→                            });
332→                        }
333→                    }
334→                }
335→            }
336→
337→            // Step the engine at fixed 60fps timestep
338→            Engine.update(engine, 1000 / 60);
339→
340→            frameCountRef.current++;
341→
342→            // Push positions to React every N frames
343→            if (frameCountRef.current % PHYSICS_CONFIG.renderEvery === 0) {
344→                const next = new Map();
345→                for (const [postId, body] of bodies.entries()) {
346→                    next.set(postId, { x: body.position.x, y: body.position.y });
347→                }
348→                setStarBodyPositions(next);
349→            }
350→
351→            // Periodic cleanup: remove bodies that have been static for too long
352→            const now = Date.now();
353→            if (now - lastCleanupRef.current > 10000) {
354→                lastCleanupRef.current = now;
355→                for (const [postId, timestamp] of staticTimes.entries()) {
356→                    if (now - timestamp > PHYSICS_CONFIG.staticTimeout) {
357→                        const body = bodies.get(postId);
358→                        if (body) {
359→                            World.remove(engine.world, body);
360→                            bodies.delete(postId);
361→                            anchors.delete(postId);
362→                        }
363→                        staticTimes.delete(postId);
364→                    }
365→                }
366→            }
367→
368→            rafRef.current = requestAnimationFrame(tick);
369→        };
370→
371→        rafRef.current = requestAnimationFrame(tick);
372→
373→        return () => {
374→            active = false;
375→            if (rafRef.current) {
376→                cancelAnimationFrame(rafRef.current);
377→                rafRef.current = null;
378→            }
379→        };
380→    }, [enabled]);
381→
382→    // ── Drag handlers ──────────────────────────────────────────────────
383→
384→    const handleStarPointerDown = useCallback((postId, screenX, screenY) => {
385→        if (!engineRef.current) return;
386→        const body = bodiesRef.current.get(postId);
387→        if (!body) return;
388→
389→        isStarDragging.current = true;
390→
391→        // Wake up the body if sleeping
392→        if (body.isSleeping) {
393→            Body.set(body, 'isSleeping', false);
394→        }
395→
396→        const worldPos = screenToWorld(
397→            screenX, screenY,
398→            cameraRef.current, zoomRef.current, stageSizeRef.current
399→        );
400→
401→        // Create a temporary fixed-point constraint
402→        dragPointRef.current = { x: worldPos.x, y: worldPos.y };
403→        dragBodyRef.current = body;
404→
405→        const constraint = Constraint.create({
406→            bodyA: body,
407→            pointB: dragPointRef.current,
408→            length: 0,
409→            stiffness: 0.1,
410→            damping: 0.05,
411→        });
412→
413→        World.add(engineRef.current.world, constraint);
414→        dragConstraintRef.current = constraint;
415→    }, []);
416→
417→    const handlePointerMove = useCallback((screenX, screenY) => {
418→        if (!isStarDragging.current || !dragConstraintRef.current) return;
419→
420→        const worldPos = screenToWorld(
421→            screenX, screenY,
422→            cameraRef.current, zoomRef.current, stageSizeRef.current
423→        );
424→
425→        // Update the constraint's fixed world point
426→        dragConstraintRef.current.pointB.x = worldPos.x;
427→        dragConstraintRef.current.pointB.y = worldPos.y;
428→    }, []);
429→
430→    const handlePointerUp = useCallback(() => {
431→        if (!isStarDragging.current) return;
432→
433→        if (dragConstraintRef.current && engineRef.current) {
434→            World.remove(engineRef.current.world, dragConstraintRef.current);
435→        }
436→
437→        dragConstraintRef.current = null;
438→        dragBodyRef.current = null;
439→        dragPointRef.current = null;
440→        isStarDragging.current = false;
441→    }, []);
442→
443→    return {
444→        starBodyPositions,
445→        handleStarPointerDown,
446→        handlePointerMove,
447→        handlePointerUp,
448→    };
449→}
