 22→} from './utils/cosmicPhysics';
 23→import { handleClickProfile } from '../../../helpers/handleClicks';
 24→import styles from './Universe.module.css';
 25→
 26→const SECTOR_SIZE = 2000;
 27→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 28→
 29→const Universe = () => {
 30→    const navigate = useNavigate();
 31→    const { user } = useAuth();
