154→        posts: postArray,
155→        starPulls,
156→        centroidByUser,
157→        activeSectorKeys,
158→        activePostIds,
159→        sectorSize: SECTOR_SIZE,
160→    });
161→
162→    // ── Star-level physics (Matter.js) ─────────────────────────────
163→    const {
164→        starBodyPositions,
165→        handleStarPointerDown,
166→        handlePointerMove: handleStarPointerMove,
167→        handlePointerUp: handleStarPointerUp,
168→    } = useStarPhysics({
169→        posts: postArray,
170→        activePostIds,
171→        galaxyPositions,
172→        starPulls,
173→        similarPairs,
174→        starPullOffsets,
175→        isGalaxySettled: isSettled,
176→        camera,
177→        zoom,
178→        stageSize,
179→        isStarDragging,
180→        enabled: !isInitialLoading,
181→    });
182→
183→    // ── Render galaxies = hash galaxies with animated positions ──────
184→    const galaxies = useMemo(() => {
185→        return hashGalaxies.map(g => {
186→            const animated = galaxyPositions.get(g.userId);
187→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
188→        });
189→    }, [hashGalaxies, galaxyPositions]);
190→
191→    // Home position for distance tracker — same resolution as auto-focus.
