 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges,
 47→    starBodyPositions, onStarDragStart,
 48→    camera, stageSize,
 49→}) => {
 50→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 51→    const galaxyUserIdMap = useMemo(() => {
 52→        const map = new Map();
 53→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 54→        return map;
 55→    }, [galaxies]);
 56→
 57→    // Galaxy spiral visuals — positioned at animated galaxy coords
 58→    const galaxyVisuals = useMemo(() =>
 59→        galaxies?.map(g => ({
 60→            x: g.x,
 61→            y: g.y,
 62→            ...generateGalaxyData(g.userId),
 63→            color: getStarColor(g.userId),
 64→        })) || []
 65→    , [galaxies]);
 66→
 67→    // ── Compute every star's render position ─────────────────────────
 68→    // Stars follow their parent galaxy's displacement from hash→animated,
 69→    // plus an optional pull offset toward similar galaxy centroids.
 70→    const computedStarPositions = useMemo(() => {
 71→        const map = new Map();
 72→        for (const post of posts) {
 73→            // Prefer physics-driven position when available
 74→            const physicsPos = starBodyPositions?.get(post.id);
 75→            if (physicsPos) {
 76→                map.set(post.id, physicsPos);
 77→                continue;
 78→            }
 79→
 80→            const uid = post.users?.id ?? post.user_id;
 81→
 82→            // Galaxy displacement: how far the galaxy moved from hash to animated
 83→            const hashGal = userHomeCoords(uid);
 84→            const animGal = galaxyPositions?.get(uid);
 85→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 86→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 87→
 88→            // Star pull offset (Gravity B)
 89→            const pull = starPullOffsets?.get(post.id);
 90→
 91→            // Base position = original hash+spiral coords
 92→            const baseX = post.universe_x ?? post.display_x;
 93→            const baseY = post.universe_y ?? post.display_y;
 94→
 95→            map.set(post.id, {
 96→                x: baseX + galDx + (pull?.dx ?? 0),
 97→                y: baseY + galDy + (pull?.dy ?? 0),
 98→            });
 99→        }
100→        return map;
101→    }, [posts, galaxyPositions, starPullOffsets, starBodyPositions]);
102→
103→    // ── Viewport culling: only render stars within visible bounds + buffer ──
104→    const visibleBounds = useMemo(() => {
105→        if (!camera || !stageSize || !zoom) return null;
106→        const halfW = (stageSize.width / 2) / zoom;
107→        const halfH = (stageSize.height / 2) / zoom;
108→        const bufferWorld = 500 / zoom;
109→        return {
110→            minX: camera.x - halfW - bufferWorld,
111→            maxX: camera.x + halfW + bufferWorld,
112→            minY: camera.y - halfH - bufferWorld,
113→            maxY: camera.y + halfH + bufferWorld,
114→        };
115→    }, [camera, stageSize, zoom]);
116→
117→    const visiblePosts = useMemo(() => {
118→        if (!visibleBounds) return posts; // fallback: render all
119→        return posts.filter(post => {
120→            const pos = computedStarPositions.get(post.id);
121→            if (!pos) return true; // keep if no position computed yet
122→            return pos.x >= visibleBounds.minX && pos.x <= visibleBounds.maxX
123→                && pos.y >= visibleBounds.minY && pos.y <= visibleBounds.maxY;
124→        });
125→    }, [posts, computedStarPositions, visibleBounds]);
126→
127→    const bridgePairs = useMemo(() => {
128→        const maxPairs = 120;
129→
130→        if (useEmbeddingBridges) {
131→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
132→                ? posts.filter((post) => activePostIds.has(post?.id))
133→                : posts;
134→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
135→        }
136→
137→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
138→
139→        return similarPairs
140→            .filter((pair) => Number(pair?.similarity) > 0.9)
141→            .filter((pair) => {
142→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
143→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
144→            })
145→            .slice(0, maxPairs);
146→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
147→
148→    return (
149→        <Layer {...layerProps}>
150→            {/* Semantic bridges between similar posts */}
151→            {bridgePairs.length > 0 && (
152→                <Shape
153→                    sceneFunc={(ctx) => {
154→                        for (const pair of bridgePairs) {
155→                            const posA = computedStarPositions.get(pair.post_a);
156→                            const posB = computedStarPositions.get(pair.post_b);
157→                            if (!posA || !posB) continue;
158→
159→                            const dx = posB.x - posA.x;
160→                            const dy = posB.y - posA.y;
161→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
162→
163→                            const mx = (posA.x + posB.x) / 2;
164→                            const my = (posA.y + posB.y) / 2;
165→                            const perpX = (-dy / dist) * dist * 0.06;
166→                            const perpY = (dx / dist) * dist * 0.06;
167→
168→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
169→                            ctx.lineWidth = 0.8;
170→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
171→                            ctx.shadowBlur = 4;
172→                            ctx.beginPath();
173→                            ctx.moveTo(posA.x, posA.y);
174→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
175→                            ctx.stroke();
176→                        }
177→                        ctx.shadowBlur = 0;
178→                    }}
179→                    perfectDrawEnabled={false}
180→                    listening={false}
181→                />
182→            )}
183→            {/* Spiral galaxy visuals + connection lines */}
184→            <Shape
185→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
186→                perfectDrawEnabled={false}
187→                listening={false}
188→            />
189→            {/* Galaxy name labels */}
190→            {galaxies?.map((g) => (
191→                <GalaxyLabel
192→                    key={g.userId}
193→                    x={g.x}
194→                    y={g.y}
195→                    name={g.name}
196→                    zoom={zoom}
197→                    onClick={() => onGalaxyClick(g)}
198→                />
199→            ))}
200→            {/* Stars (viewport-culled) */}
201→            {visiblePosts.map((post) => {
202→                const postUserId = post.users?.id ?? post.user_id;
203→                const color = getStarColor(postUserId);
204→                const likeCount = post.like_count != null
205→                    ? post.like_count
206→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
207→                const radius = getStarRadius(likeCount);
208→
209→                const pos = computedStarPositions.get(post.id);
210→                const x = pos?.x ?? post.universe_x ?? post.display_x;
211→                const y = pos?.y ?? post.universe_y ?? post.display_y;
212→
213→                return (
214→                    <StarGroup
215→                        key={post.id}
216→                        x={x}
217→                        y={y}
218→                        radius={radius}
219→                        color={color}
220→                        title={post.title}
221→                        showTitle={showTitles}
222→                        isPulsing={pulsingId === post.id}
223→                        onClick={() => onStarClick(post)}
224→                        onPointerDown={onStarDragStart ? (screenX, screenY) => onStarDragStart(post.id, screenX, screenY) : undefined}
225→                    />
226→                );
227→            })}
228→        </Layer>
229→    );
230→});
231→
232→InteractiveLayer.displayName = 'InteractiveLayer';
233→
234→export default InteractiveLayer;
