  1→import Matter from 'matter-js';
  2→
  3→const { Engine, Bodies, Body, Constraint, World } = Matter;
  4→
  5→export const PHYSICS_CONFIG = {
  6→    constraintStiffness: 0.005,
  7→    constraintDamping: 0.1,
  8→    frictionAir: 0.03,
  9→    restitution: 0.4,
 10→    sleepThreshold: 120,
 11→    maxActiveBodies: 600,
 12→    renderEvery: 3,
 13→    cleanupInterval: 30000,
 14→    staticTimeout: 30000,
 15→    constraintBaseLength: 40,
 16→    constraintLengthRange: 120,
 17→    nBodyG: 2,
 18→    nBodyTheta: 0.5,
 19→    nBodySoftening: 30,
 20→    nBodyMaxForce: 0.008,
 21→    orbitSpringK: 0.0004,   // radial spring — holds posts at their natural orbit radius
 22→    orbitalDrive: 0.0008,   // tangential push — maintains gentle rotation (~5 min per orbit at r=80)
 23→};
 24→
 25→export function createStarEngine() {
 26→    const engine = Engine.create({
 27→        gravity: { x: 0, y: 0 },
 28→        enableSleeping: true,
 29→    });
 30→
 31→    engine.timing.timeScale = 1;
 32→
 33→    return engine;
 34→}
 35→
 36→export function createStarBody(postId, x, y, radius, mass) {
 37→    const body = Bodies.circle(x, y, radius, {
 38→        label: postId,
 39→        mass,
 40→        frictionAir: PHYSICS_CONFIG.frictionAir,
 41→        restitution: PHYSICS_CONFIG.restitution,
 42→        sleepThreshold: PHYSICS_CONFIG.sleepThreshold,
 43→    });
 44→
 45→    return body;
 46→}
 47→
 48→export function createConstellationConstraint(bodyA, bodyB, similarity) {
 49→    const length =
 50→        PHYSICS_CONFIG.constraintBaseLength +
 51→        (1 - similarity) * PHYSICS_CONFIG.constraintLengthRange;
 52→
 53→    return Constraint.create({
 54→        bodyA,
 55→        bodyB,
 56→        length,
 57→        stiffness: PHYSICS_CONFIG.constraintStiffness,
 58→        damping: PHYSICS_CONFIG.constraintDamping,
 59→        render: { visible: false },
 60→    });
 61→}
