 69→/**
 70→ * Virtual mass for a galaxy center in the N-body simulation.
 71→ * Scales with how many posts the user has.
 72→ */
 73→export function getGalaxyMass(postCount) {
 74→    return 10 + (postCount || 0) * 2;
