 77→/**
 78→ * Compute initial orbital velocity for a star around its galaxy center.
 79→ * Gives stars tangential velocity so they orbit rather than collapse.
 80→ */
 81→export function computeOrbitalVelocity(starPos, galaxyCenterPos, galaxyMass) {
 82→    const dx = starPos.x - galaxyCenterPos.x;
 83→    const dy = starPos.y - galaxyCenterPos.y;
 84→    const r = Math.sqrt(dx * dx + dy * dy);
 85→    const safeR = Math.max(r, PHYSICS_CONFIG.nBodySoftening);
 86→
 87→    const v = Math.sqrt(PHYSICS_CONFIG.nBodyG * galaxyMass / safeR);
 88→
 89→    // Perpendicular direction (90° rotation of radial vector)
 90→    const invR = r > 0 ? 1 / r : 0;
 91→    const dirX = -dy * invR; // perpendicular x
 92→    const dirY = dx * invR;  // perpendicular y
 93→
 94→    // Start at 25% of full orbital velocity — gravity will shape the orbit
 95→    const scale = 0.25;
 96→    // ±10% random perturbation to prevent perfect circles
 97→    const perturbation = 0.9 + Math.random() * 0.2;
 98→
 99→    return {
100→        vx: dirX * v * scale * perturbation,
101→        vy: dirY * v * scale * perturbation,
102→    };
103→}
