  2→ * Barnes-Hut N-body gravity engine.
  3→ * Pure math — no React or Matter.js dependency.
  4→ */
  5→
  6→// ── Config ────────────────────────────────────────────────────────────
  7→export const THETA = 0.5;          // Barnes-Hut opening angle
  8→export const G_BASE = 2;           // Gravitational constant (tuned for 50k×50k world, mass ~1–4)
  9→export const SOFTENING = 50;       // Prevents singularity at close range
 10→export const MAX_FORCE = 0.008;    // Per-axis clamp to prevent explosions
 11→
 12→// ── Semantic G scaling ────────────────────────────────────────────────
 13→export function computeSemanticG(baseG, similarity) {
 14→    if (similarity > 0.8) return baseG * 3.0;
 15→    if (similarity >= 0.2) return baseG * (1 + similarity);
 16→    return baseG * -0.3; // light repulsion for unrelated content
 17→}
 18→
 19→// ── QuadTree Node ─────────────────────────────────────────────────────
 20→class QuadTreeNode {
 21→    constructor(x, y, w, h) {
 22→        this.bounds = { x, y, w, h }; // top-left corner + dimensions
 23→        this.centerOfMass = { x: 0, y: 0 };
 24→        this.totalMass = 0;
 25→        this.body = null;       // only set on leaf with a single body
 26→        this.children = null;   // [NW, NE, SW, SE] when subdivided
 27→        this.bodyCount = 0;
 28→    }
 29→
 30→    _subdivide() {
 31→        const { x, y, w, h } = this.bounds;
 32→        const hw = w / 2;
 33→        const hh = h / 2;
 34→        this.children = [
 35→            new QuadTreeNode(x, y, hw, hh),          // NW
 36→            new QuadTreeNode(x + hw, y, hw, hh),     // NE
 37→            new QuadTreeNode(x, y + hh, hw, hh),     // SW
 38→            new QuadTreeNode(x + hw, y + hh, hw, hh) // SE
 39→        ];
 40→    }
 41→
 42→    _getQuadrant(bx, by) {
 43→        const { x, y, w, h } = this.bounds;
 44→        const midX = x + w / 2;
 45→        const midY = y + h / 2;
 46→        if (bx < midX) {
 47→            return by < midY ? 0 : 2; // NW or SW
 48→        }
 49→        return by < midY ? 1 : 3;     // NE or SE
 50→    }
 51→
 52→    insert(body) {
 53→        // Empty node — just store the body
 54→        if (this.bodyCount === 0 && !this.children) {
 55→            this.body = body;
 56→            this.bodyCount = 1;
 57→            return;
 58→        }
 59→
 60→        // Leaf with one body — need to subdivide
 61→        if (this.body && !this.children) {
 62→            // Don't subdivide below a minimum size to avoid infinite recursion
 63→            if (this.bounds.w < 1 || this.bounds.h < 1) {
 64→                this.bodyCount++;
 65→                return;
 66→            }
 67→            this._subdivide();
 68→            // Re-insert the existing body
 69→            const existing = this.body;
 70→            this.body = null;
 71→            const qi = this._getQuadrant(existing.x, existing.y);
 72→            this.children[qi].insert(existing);
 73→        }
 74→
 75→        // Internal node — insert into correct child
 76→        if (!this.children) {
 77→            this._subdivide();
 78→        }
 79→        const qi = this._getQuadrant(body.x, body.y);
 80→        this.children[qi].insert(body);
 81→        this.bodyCount++;
 82→    }
 83→
 84→    computeMass() {
 85→        if (this.bodyCount === 0) return;
 86→
 87→        // Leaf node
 88→        if (this.body) {
 89→            this.centerOfMass.x = this.body.x;
 90→            this.centerOfMass.y = this.body.y;
 91→            this.totalMass = this.body.mass;
 92→            return;
 93→        }
 94→
 95→        // Internal node — aggregate from children
 96→        let mx = 0, my = 0, tm = 0;
 97→        if (this.children) {
 98→            for (const child of this.children) {
 99→                if (child.bodyCount === 0) continue;
100→                child.computeMass();
101→                mx += child.centerOfMass.x * child.totalMass;
102→                my += child.centerOfMass.y * child.totalMass;
103→                tm += child.totalMass;
104→            }
105→        }
106→        if (tm > 0) {
107→            this.centerOfMass.x = mx / tm;
108→            this.centerOfMass.y = my / tm;
109→            this.totalMass = tm;
110→        }
111→    }
112→}
113→
114→// ── Build QuadTree ────────────────────────────────────────────────────
115→/**
116→ * @param {Array<{id, x, y, mass}>} bodies
117→ * @returns {QuadTreeNode} root
118→ */
119→export function buildQuadTree(bodies) {
120→    if (!bodies || bodies.length === 0) return null;
121→
122→    // Compute bounding box with padding
123→    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
124→    for (const b of bodies) {
125→        if (b.x < minX) minX = b.x;
126→        if (b.y < minY) minY = b.y;
127→        if (b.x > maxX) maxX = b.x;
128→        if (b.y > maxY) maxY = b.y;
129→    }
130→
131→    const padding = 100;
132→    minX -= padding;
133→    minY -= padding;
134→    maxX += padding;
135→    maxY += padding;
136→
137→    // Make it square (quadtree requirement)
138→    const size = Math.max(maxX - minX, maxY - minY);
139→
140→    const root = new QuadTreeNode(minX, minY, size, size);
141→
142→    for (const b of bodies) {
143→        root.insert(b);
144→    }
145→
146→    root.computeMass();
147→    return root;
148→}
149→
150→// ── Compute Barnes-Hut Forces ─────────────────────────────────────────
151→/**
152→ * @param {QuadTreeNode} root
153→ * @param {Array<{id, x, y, mass}>} bodies
154→ * @param {Object} options - { G, theta, softening, maxForce, pairMap }
155→ * @returns {Map<id, {fx, fy}>}
156→ */
157→export function computeBarnesHutForces(root, bodies, options = {}) {
158→    const {
159→        G = G_BASE,
160→        theta = THETA,
161→        softening = SOFTENING,
162→        maxForce = MAX_FORCE,
163→        pairMap = null,
164→    } = options;
165→
166→    const forces = new Map();
167→    if (!root) return forces;
168→
169→    for (const body of bodies) {
170→        let fx = 0, fy = 0;
171→
172→        const stack = [root];
173→        while (stack.length > 0) {
174→            const node = stack.pop();
175→            if (node.bodyCount === 0) continue;
176→
177→            // Skip self
178→            if (node.body && node.body.id === body.id) continue;
179→
180→            const dx = node.centerOfMass.x - body.x;
181→            const dy = node.centerOfMass.y - body.y;
182→            const distSq = dx * dx + dy * dy;
183→            const dist = Math.sqrt(distSq);
184→
185→            // External node (leaf) — direct force
186→            if (node.body) {
187→                const softenedDistSq = distSq + softening * softening;
188→                // Look up semantic similarity for direct interactions
189→                let effectiveG = G;
190→                if (pairMap) {
191→                    const pairs = pairMap.get(body.id);
192→                    if (pairs) {
193→                        for (const p of pairs) {
194→                            if (p.otherPostId === node.body.id) {
195→                                effectiveG = computeSemanticG(G, p.similarity);
196→                                break;
197→                            }
198→                        }
199→                    }
200→                }
201→                const F = effectiveG * body.mass * node.totalMass / softenedDistSq;
202→                const invDist = dist > 0 ? 1 / dist : 0;
203→                fx += F * dx * invDist;
204→                fy += F * dy * invDist;
205→                continue;
206→            }
207→
208→            // Internal node — check if far enough to approximate
209→            const nodeWidth = node.bounds.w;
210→            if (dist > 0 && nodeWidth / dist < theta) {
211→                // Treat as point mass (use base G for aggregate)
212→                const softenedDistSq = distSq + softening * softening;
213→                const F = G * body.mass * node.totalMass / softenedDistSq;
214→                const invDist = 1 / dist;
215→                fx += F * dx * invDist;
216→                fy += F * dy * invDist;
217→                continue;
218→            }
219→
220→            // Too close — recurse into children
221→            if (node.children) {
222→                for (const child of node.children) {
223→                    if (child.bodyCount > 0) stack.push(child);
224→                }
225→            }
226→        }
227→
228→        // Clamp force per axis
229→        fx = Math.max(-maxForce, Math.min(maxForce, fx));
230→        fy = Math.max(-maxForce, Math.min(maxForce, fy));
231→
232→        forces.set(body.id, { fx, fy });
233→    }
234→
235→    return forces;
236→}
