  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { getStarColor } from '../utils/starUtils';
  3→import styles from '../Universe.module.css';
  4→
  5→const MINIMAP_SIZE = 160;
  6→const WORLD_MIN = -25000;
  7→const WORLD_MAX = 25000;
  8→const WORLD_RANGE = WORLD_MAX - WORLD_MIN;
  9→
 10→/** Convert world coordinate to minimap pixel */
 11→const worldToMinimap = (val) =>
 12→    ((val - WORLD_MIN) / WORLD_RANGE) * MINIMAP_SIZE;
 13→
 14→/** Convert minimap pixel to world coordinate */
 15→const minimapToWorld = (px) =>
 16→    (px / MINIMAP_SIZE) * WORLD_RANGE + WORLD_MIN;
 17→
 18→const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
 19→
 20→const UniverseMinimap = React.memo(({ galaxies, camera, zoom, stageSize, onNavigate }) => {
 21→    const canvasRef = useRef(null);
 22→    const pointerStateRef = useRef({
 23→        active: false,
 24→        pointerId: null,
 25→        moved: false,
 26→        startX: 0,
 27→        startY: 0,
 28→    });
 29→
 30→    useEffect(() => {
 31→        const canvas = canvasRef.current;
 32→        if (!canvas) return;
 33→
 34→        const ctx = canvas.getContext('2d');
 35→        const dpr = window.devicePixelRatio || 1;
 36→
 37→        canvas.width = MINIMAP_SIZE * dpr;
 38→        canvas.height = MINIMAP_SIZE * dpr;
 39→        ctx.scale(dpr, dpr);
 40→
 41→        // Background
 42→        ctx.fillStyle = 'rgba(10, 14, 26, 0.85)';
 43→        ctx.fillRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);
 44→
 45→        // Galaxy dots
 46→        if (galaxies) {
 47→            for (const g of galaxies) {
 48→                const mx = worldToMinimap(g.x);
 49→                const my = worldToMinimap(g.y);
 50→
 51→                ctx.fillStyle = getStarColor(g.userId);
 52→                ctx.globalAlpha = 0.7;
 53→                ctx.beginPath();
 54→                ctx.arc(mx, my, 1.5, 0, Math.PI * 2);
 55→                ctx.fill();
 56→            }
 57→        }
 58→
 59→        ctx.globalAlpha = 1;
 60→
 61→        // Viewport rectangle
 62→        if (camera && stageSize) {
 63→            // Camera is the world-space center, zoom determines how much world is visible
 64→            const viewWidth = stageSize.width / zoom;
 65→            const viewHeight = stageSize.height / zoom;
 66→
 67→            const vpLeft = worldToMinimap(camera.x - viewWidth / 2);
 68→            const vpTop = worldToMinimap(camera.y - viewHeight / 2);
 69→            const vpW = (viewWidth / WORLD_RANGE) * MINIMAP_SIZE;
 70→            const vpH = (viewHeight / WORLD_RANGE) * MINIMAP_SIZE;
 71→
 72→            ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
 73→            ctx.lineWidth = 1;
 74→            ctx.strokeRect(vpLeft, vpTop, vpW, vpH);
 75→        }
 76→
 77→        // Border
 78→        ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
 79→        ctx.lineWidth = 1;
 80→        ctx.strokeRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);
 81→
 82→    }, [galaxies, camera, zoom, stageSize]);
 83→
 84→    const navigateFromClientPoint = useCallback((clientX, clientY, mode = 'fly') => {
 85→        const canvas = canvasRef.current;
 86→        if (!canvas || !onNavigate) return;
 87→
 88→        const rect = canvas.getBoundingClientRect();
 89→        if (!rect.width || !rect.height) return;
 90→
 91→        const scaleX = MINIMAP_SIZE / rect.width;
 92→        const scaleY = MINIMAP_SIZE / rect.height;
 93→
 94→        const px = clamp((clientX - rect.left) * scaleX, 0, MINIMAP_SIZE);
 95→        const py = clamp((clientY - rect.top) * scaleY, 0, MINIMAP_SIZE);
 96→
 97→        const worldX = minimapToWorld(px);
 98→        const worldY = minimapToWorld(py);
 99→
100→        onNavigate(worldX, worldY, mode);
101→    }, [onNavigate]);
102→
103→    const handlePointerDown = useCallback((e) => {
104→        const canvas = canvasRef.current;
105→        if (!canvas) return;
106→
107→        e.preventDefault();
108→        e.stopPropagation();
109→
110→        pointerStateRef.current = {
111→            active: true,
112→            pointerId: e.pointerId,
113→            moved: false,
114→            startX: e.clientX,
115→            startY: e.clientY,
116→        };
117→
118→        if (canvas.setPointerCapture) {
119→            canvas.setPointerCapture(e.pointerId);
120→        }
121→    }, []);
122→
123→    const handlePointerMove = useCallback((e) => {
124→        const state = pointerStateRef.current;
125→        if (!state.active || state.pointerId !== e.pointerId) return;
126→
127→        e.preventDefault();
128→        e.stopPropagation();
129→
130→        const movedEnough = Math.hypot(e.clientX - state.startX, e.clientY - state.startY) > 2;
131→        if (!movedEnough && !state.moved) return;
132→
133→        state.moved = true;
134→        navigateFromClientPoint(e.clientX, e.clientY, 'drag');
135→    }, [navigateFromClientPoint]);
136→
137→    const finishPointer = useCallback((e) => {
138→        const state = pointerStateRef.current;
139→        if (!state.active || state.pointerId !== e.pointerId) return;
140→
141→        e.preventDefault();
142→        e.stopPropagation();
143→
144→        if (state.moved) {
145→            navigateFromClientPoint(e.clientX, e.clientY, 'drag');
146→        } else {
147→            navigateFromClientPoint(e.clientX, e.clientY, 'fly');
148→        }
149→
150→        const canvas = canvasRef.current;
151→        if (canvas?.releasePointerCapture) {
152→            canvas.releasePointerCapture(e.pointerId);
153→        }
154→
155→        pointerStateRef.current = {
156→            active: false,
157→            pointerId: null,
158→            moved: false,
159→            startX: 0,
160→            startY: 0,
161→        };
162→    }, [navigateFromClientPoint]);
163→
164→    const handleContextMenu = useCallback((e) => {
165→        e.preventDefault();
166→    }, []);
167→
168→    return (
169→        <canvas
170→            ref={canvasRef}
171→            className={styles.minimap}
172→            width={MINIMAP_SIZE}
173→            height={MINIMAP_SIZE}
174→            onPointerDown={handlePointerDown}
175→            onPointerMove={handlePointerMove}
176→            onPointerUp={finishPointer}
177→            onPointerCancel={finishPointer}
178→            onPointerLeave={finishPointer}
179→            onContextMenu={handleContextMenu}
180→            title="Click to fly, drag to pan"
181→        />
182→    );
183→});
184→
185→UniverseMinimap.displayName = 'UniverseMinimap';
186→
187→export default UniverseMinimap;
188→

