187→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
188→        });
189→    }, [hashGalaxies, galaxyPositions]);
190→
191→    // Home position for distance tracker — same resolution as auto-focus.
192→    const homePosition = useMemo(() => {
193→        if (!userId) return { x: 0, y: 0 };
194→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
195→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
196→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
197→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
198→
199→    const getComputedStarPosition = useCallback((post) => {
200→        if (!post) return null;
201→
202→        // Prefer physics-driven position when available
203→        const physicsPos = starBodyPositions.get(post.id);
204→        if (physicsPos) return physicsPos;
205→
206→        const uid = post.users?.id ?? post.user_id;
207→        const hashGal = userHomeCoords(uid);
208→        const animGal = galaxyPositions.get(uid);
209→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
210→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
211→        const pull = starPullOffsets.get(post.id);
212→
213→        const baseX = post.universe_x ?? post.display_x;
214→        const baseY = post.universe_y ?? post.display_y;
215→        if (baseX == null || baseY == null) return null;
216→
217→        return {
218→            x: baseX + galDx + (pull?.dx ?? 0),
219→            y: baseY + galDy + (pull?.dy ?? 0),
220→        };
221→    }, [galaxyPositions, starPullOffsets, starBodyPositions]);
222→
223→    // Resolve logged-in user's galaxy target independently from viewport data.
224→    useEffect(() => {
225→        if (!userId) return;
226→        if (ownGalaxyLookupStartedRef.current) return;
227→
228→        ownGalaxyLookupStartedRef.current = true;
229→        let cancelled = false;
230→
231→        const resolveOwnGalaxyTarget = async () => {
232→            try {
233→                const { data, error } = await supabase
234→                    .from('galaxy_centroids')
235→                    .select('galaxy_x, galaxy_y')
236→                    .eq('user_id', userId)
237→                    .maybeSingle();
238→
239→                if (cancelled) return;
240→
241→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
242→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
243→                    setHasOwnPosts(true);
244→                    return;
245→                }
246→            } catch (err) {
247→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
248→            }
249→
250→            if (!cancelled) {
251→                setOwnGalaxyTarget(userHomeCoords(userId));
252→            }
253→        };
254→
255→        resolveOwnGalaxyTarget();
256→
257→        return () => {
258→            cancelled = true;
259→        };
260→    }, [userId]);
261→
262→    // One-time wormhole fetch on mount
263→    useEffect(() => {
264→        let cancelled = false;
265→
266→        const fetchWormholes = async () => {
267→            try {
268→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
269→                    similarity_threshold: 0.7,
270→                    min_distance: 0,
271→                    max_pairs: 30,
272→                });
273→                if (cancelled) return;
274→                if (error) {
275→                    console.warn('[universe] wormhole fetch error:', error.message);
276→                    return;
277→                }
278→                console.log('[universe] wormhole pairs:', data);
279→                if (Array.isArray(data) && data.length > 0) {
280→                    setWormholes(data);
281→                }
282→            } catch (err) {
283→                if (!cancelled) {
284→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
285→                }
286→            }
287→        };
288→
289→        fetchWormholes();
290→        return () => { cancelled = true; };
291→    }, []);
292→
293→    // Debounced fetch on camera/zoom change
294→    useEffect(() => {
295→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
296→
297→        fetchDebounceRef.current = setTimeout(async () => {
298→            const bounds = getViewportBounds();
299→            try {
300→                const result = await getUniversePosts(
301→                    bounds.minX,
302→                    bounds.maxX,
303→                    bounds.minY,
304→                    bounds.maxY,
305→                    200
306→                );
307→                if (result?.data) {
308→                    setPosts(prev => {
309→                        const next = new Map(prev);
310→                        for (const post of result.data) {
311→                            next.set(post.id, post);
312→                        }
313→                        return next;
314→                    });
315→                    if (userId && hasOwnPosts !== true) {
316→                        const ownsAny = result.data.some(p =>
317→                            (p.users?.id ?? p.user_id) === userId
318→                        );
319→                        if (ownsAny) setHasOwnPosts(true);
320→                    }
321→                }
322→                // Keep server gravity data as fallback when embeddings are absent in payload.
323→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
324→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
325→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
326→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
327→            } catch (err) {
328→                console.error('Failed to fetch universe posts:', err);
329→            } finally {
330→                if (!initialFetchResolvedRef.current) {
331→                    initialFetchResolvedRef.current = true;
332→                    setIsInitialLoading(false);
333→                }
334→            }
335→        }, 400);
336→
337→        return () => {
338→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
339→        };
340→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
341→
342→    const handleStarClick = useCallback((post) => {
343→        if (isFlying.current) return;
344→        setSelectedPost(post);
345→        setSelectedGalaxy(null);
346→        setGalaxyProfile(null);
347→
348→        const position = getComputedStarPosition(post);
349→        if (!position) return;
350→
351→        flyTo(position.x, position.y, 1.2, () => {
352→            setPulsingId(post.id);
353→            setTimeout(() => setPulsingId(null), 700);
354→        });
355→    }, [flyTo, getComputedStarPosition, isFlying]);
356→
357→    const handleGalaxyClick = useCallback(async (galaxy) => {
358→        if (isFlying.current) return;
359→        setSelectedGalaxy(galaxy);
360→        setSelectedPost(null);
361→        setGalaxyProfile(null);
362→        flyTo(galaxy.x, galaxy.y, 0.8);
363→
364→        try {
365→            const data = await getUserData(galaxy.userId);
366→            const profile = data?.userData?.[0] || null;
367→            setGalaxyProfile(profile);
368→        } catch (err) {
369→            console.error('Failed to fetch galaxy profile:', err);
370→        }
371→    }, [flyTo, isFlying]);
372→
373→    const handleReadPost = useCallback(() => {
374→        if (!selectedPost) return;
375→        navigate(`/home/post/${selectedPost.id}`);
376→    }, [selectedPost, navigate]);
377→
378→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
379→        if (mode === 'drag') {
380→            jumpTo(worldX, worldY);
381→            return;
382→        }
383→        flyTo(worldX, worldY, zoom);
384→    }, [flyTo, jumpTo, zoom]);
385→
386→    // Enrich wormhole positions with live gravity-computed post coords
387→    const enrichedWormholes = useMemo(() => {
388→        return wormholes.map(wh => {
389→            const postA = posts.get(wh.post_a);
390→            const postB = posts.get(wh.post_b);
391→            const posA = postA ? getComputedStarPosition(postA) : null;
392→            const posB = postB ? getComputedStarPosition(postB) : null;
393→            return {
394→                ...wh,
395→                a_x: posA?.x ?? wh.a_x,
396→                a_y: posA?.y ?? wh.a_y,
397→                b_x: posB?.x ?? wh.b_x,
398→                b_y: posB?.y ?? wh.b_y,
399→            };
400→        });
401→    }, [wormholes, posts, getComputedStarPosition]);
402→
403→    // Find wormhole connection for a given post (if any)
404→    const getWormholeForPost = useCallback((postId) => {
405→        if (!postId || enrichedWormholes.length === 0) return null;
406→        for (const wh of enrichedWormholes) {
407→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
408→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
409→        }
410→        return null;
411→    }, [enrichedWormholes]);
412→
413→    const handleWormholeTravel = useCallback(() => {
414→        if (!selectedPost || isFlying.current) return;
415→        const match = getWormholeForPost(selectedPost.id);
416→        if (!match) return;
417→        const { wormhole, side } = match;
418→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
419→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
420→        setSelectedPost(null);
421→        setIsWarping(true);
422→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
423→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
424→
425→    // One-time auto focus after first payload is loaded.
426→    useEffect(() => {
427→        if (!userId) return;
428→        if (isInitialLoading) return;
429→        if (hasAutoFocusedOwnGalaxyRef.current) return;
430→
431→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
432→        const target = ownGalaxy
433→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
434→            : (centroidTargets.get(userId) || ownGalaxyTarget);
435→
436→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
437→        if (!target) return;
438→
439→        hasAutoFocusedOwnGalaxyRef.current = true;
440→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
441→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
442→
443→    const settledPayload = useMemo(() => {
444→        if (!isSettled || activePosts.length === 0) return [];
445→
446→        const payload = [];
447→        for (const post of activePosts) {
448→            if (!post?.id) continue;
449→            const pos = getComputedStarPosition(post);
450→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
451→
452→            payload.push({
453→                post_id: post.id,
454→                settled_x: Math.round(pos.x * 100) / 100,
455→                settled_y: Math.round(pos.y * 100) / 100,
456→            });
457→        }
458→
459→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
460→        return payload;
461→    }, [activePosts, getComputedStarPosition, isSettled]);
462→
463→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
464→    useEffect(() => {
465→        if (!ENABLE_SETTLED_RPC_SAVE) return;
466→        if (!isSettled || settledPayload.length === 0) return;
467→
468→        const signature = JSON.stringify(settledPayload);
469→        if (signature === lastSettledPayloadRef.current) return;
470→
471→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
472→        settleDebounceRef.current = setTimeout(async () => {
473→            lastSettledPayloadRef.current = signature;
474→            try {
475→                const { error } = await supabase.rpc('save_universe_settled_positions', {
476→                    positions_payload: settledPayload,
477→                });
478→                if (error) {
479→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
480→                }
481→            } catch (err) {
482→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
483→            }
484→        }, 1200);
485→
486→        return () => {
487→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
488→        };
489→    }, [isSettled, settledPayload]);
490→
491→    useEffect(() => {
492→        return () => {
493→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
494→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
495→        };
496→    }, []);
497→
498→    return (
499→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
500→            <button className={styles.backButton} onClick={() => navigate('/home')}>
501→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
502→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
503→                </svg>
504→                Back
505→            </button>
506→
507→            <div className={styles.distanceTracker}>
508→                {(() => {
509→                    const dx = centerWorld.x - homePosition.x;
510→                    const dy = centerWorld.y - homePosition.y;
511→                    const dist = Math.round(Math.sqrt(dx * dx + dy * dy));
