513→                        ? 'Home'
514→                        : `${dist.toLocaleString()} Lightyears from Home`;
515→                })()}
516→            </div>
517→
518→            {isInitialLoading && (
519→                <div className={styles.loadingOverlay}>
520→                    <div className={styles.loadingCard}>
521→                        <div className={styles.loadingSpinner} />
